// ================================================
// AGGREGATE STATS - Build dashboard data
// ================================================

const allItems = $input.all();
const leads = allItems.map(i => i.json).filter(l => l.chat_id);

// Count by status
const statusCounts = {
  new: 0,
  cold: 0,
  warm: 0,
  hot: 0,
  consultation_booked: 0,
  handed_off: 0
};

for (const lead of leads) {
  if (statusCounts.hasOwnProperty(lead.status)) {
    statusCounts[lead.status]++;
  }
}

// Recent leads (last 10)
const recentLeads = leads
  .filter(l => l.last_contact)
  .sort((a, b) => new Date(b.last_contact) - new Date(a.last_contact))
  .slice(0, 10)
  .map(l => ({
    name: l.first_name || 'Unknown',
    username: l.username || '',
    status: l.status,
    budget: (l.budget_min || l.budget_max) ? 'AED ' + (l.budget_min || '?') + ' - ' + (l.budget_max || '?') : 'Not specified',
    style: l.style_preference || 'Not specified',
    artwork_type: l.artwork_type || 'Not specified',
    space_type: l.space_type || 'Not specified',
    quantity: l.quantity || '1',
    timeline: l.timeline || 'Not specified',
    purpose: l.purpose || 'Not specified',
    messages: parseInt(l.message_count) || 0,
    last_contact: l.last_contact,
    first_contact: l.first_contact
  }));

// Hot leads (priority list)
const hotLeads = leads
  .filter(l => l.status === 'hot')
  .map(l => ({
    name: l.first_name || 'Unknown',
    username: l.username ? '@' + l.username : 'N/A',
    budget: (l.budget_min || l.budget_max) ? 'AED ' + (l.budget_min || '?') + ' - ' + (l.budget_max || '?') : 'Not specified',
    style: l.style_preference || 'Not specified',
    artwork_type: l.artwork_type || 'Not specified',
    timeline: l.timeline || 'Not specified',
    last_contact: l.last_contact
  }));

// Conversion metrics
const totalLeads = leads.length;
const convertedLeads = leads.filter(l => ['consultation_booked', 'handed_off'].includes(l.status)).length;
const conversionRate = totalLeads > 0 ? ((convertedLeads / totalLeads) * 100).toFixed(1) : '0.0';

// Average messages per lead
const totalMessages = leads.reduce((sum, l) => sum + (parseInt(l.message_count) || 0), 0);
const avgMessages = totalLeads > 0 ? (totalMessages / totalLeads).toFixed(1) : '0';

// Leads today
const today = new Date();
today.setHours(0, 0, 0, 0);
const leadsToday = leads.filter(l => {
  const fc = new Date(l.first_contact);
  return fc >= today;
}).length;

// Leads this week
const weekAgo = new Date();
weekAgo.setDate(weekAgo.getDate() - 7);
const leadsThisWeek = leads.filter(l => {
  const fc = new Date(l.first_contact);
  return fc >= weekAgo;
}).length;

const dashboard = {
  summary: {
    total_leads: totalLeads,
    leads_today: leadsToday,
    leads_this_week: leadsThisWeek,
    conversion_rate: conversionRate + '%',
    avg_messages_per_lead: avgMessages,
    total_messages: totalMessages
  },
  by_status: statusCounts,
  hot_leads: hotLeads,
  recent_leads: recentLeads,
  generated_at: new Date().toISOString()
};

return [{ json: dashboard }];
